"""
mkt-original — Proverbs 16–18 (85 verses)
Run: python3 scripts/zc-original-proverbs-16-18.py
Ch16: Divine sovereignty over human plans (v1,9,33); royal theology (v10-15);
  pride/humility (v18-19); slow to anger (v32); lot = YHWH (v33).
Ch17: Testing of hearts (v3); covers transgression (v9); friend/brother (v17);
  joyful heart as medicine (v22); restrained speech (v27-28).
Ch18: Strong tower of YHWH's name (v10); death/life in tongue (v21); wife as favor (v22).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PROVERBS = {
  "16": {
    "1": "<p>'The plans (<em>ma'arĕkê</em>) of the heart belong to man, but the answer (<em>ma'anēh</em>) of the tongue is from the LORD' — the verse turns on a contrast between human intention and divine determination of what actually comes out in speech. <em>Ma'arĕkê</em> = arrangements/orderings; <em>ma'anēh</em> = the actual answer/response. YHWH controls not just big history but the specific words that leave the mouth, which Proverbs regards as the most revealing indicator of a person's inner state.</p>",
    "2": "<p><em>Kol-darkê-'îš zak bĕ'ênāyw</em> = 'All the ways of a man are pure in his own eyes' — radical self-assessment blindness. <em>Tōkēn rûḥôt YHWH</em> = 'but the LORD weighs/measures spirits.' <em>Tākan</em> (weigh/measure) is the precision-metrological verb used for calibrating scales — YHWH applies exact measurement to what humans cannot objectively assess in themselves.</p>",
    "3": "<p><em>Gōl 'el-YHWH ma'ăśeḵā</em> = 'Roll your works to the LORD' — <em>gāll</em> (roll) is used for rolling away a stone or off-loading a burden; the visual image is of handing the whole weight of one's enterprises to YHWH. <em>Wĕyikkōnû maḥšĕbōteḵā</em> = 'and your plans will be established' — the MKT 'Commit your work' captures the intent but loses the rolling/burden-transfer image.</p>",
    "4": "<p><em>Kōl pā'al YHWH lamma'anēhû</em> = 'The LORD has made everything for its purpose/answer' — <em>ma'anēhû</em> (its answer/purpose) echoes <em>ma'anēh</em> in v1: everything has its fitting response in the divine order. <em>Wĕgam-rāšā' lĕyôm rā'āh</em> = 'even the wicked for the day of calamity' — divine sovereignty extends over human wickedness itself, which serves its appointed function in YHWH's purposes without YHWH being the author of the wickedness.</p>",
    "5": "<p><em>Tô'ăbat YHWH kol-gĕbah-lēb</em> = 'An abomination to the LORD is every proud-of-heart person' — <em>gābah</em> (be high/exalted) applied to the heart describes arrogance. <em>Yād lĕyād</em> = 'hand to hand' = a certain/sure oath gesture; the proud will certainly not go unpunished.</p>",
    "6": "<p><em>Bĕḥesed we'ĕmet yĕkuppar 'āwōn</em> = 'By steadfast love and faithfulness (<em>ḥesed we'emet</em>) iniquity is atoned for/covered' — the covenant-pair terms here function as the moral rather than cultic means of atonement: the person of covenant-loyalty finds their sin covered. <em>Yĕsūr mērā'</em> = 'turns away from evil' — the fear of YHWH is the practical instrument of moral departure from evil.</p>",
    "7": "<p>'When a man's ways please the LORD, he makes even his enemies be at peace with him' — <em>yašlîm</em> (make peace) — even hostile third parties become instruments of divine blessing when a person's life is aligned with YHWH's ways. This is the positive application of divine sovereignty: YHWH controls the dispositions of enemies.</p>",
    "8": "<p>A better-than saying: 'Better a little with righteousness than great revenues with injustice' (<em>bĕṣĕdāqāh</em>). The principle of qualitative over quantitative measurement runs through Proverbs; <em>ṣĕdāqāh</em> (righteousness/right-relationship) modifies the value of what is possessed.</p>",
    "9": "<p><em>Lēb 'ādām yĕḥaššēb darkô</em> = 'The heart of a man plans his way' — the verb <em>ḥāšab</em> is the word for careful calculation/devising; <em>wĕYHWH yākîn ṣa'ădô</em> = 'but the LORD establishes his step.' <em>Ṣa'ăd</em> (step/stride) is the individual footfall — YHWH's providential control is not merely over large trajectories but over each specific step. The contrast of human planning with divine directing is the governing theme of ch16.</p>",
    "10": "<p><em>Qesem 'al-śiptê-melek</em> = 'Divination/oracle is on the lips of the king' — <em>qesem</em> normally refers to prohibited divination (Deut 18:10), but here it is used positively for the quasi-oracular authority of the king's judicial pronouncements. The royal mouth speaks with binding authority; <em>bĕmišpāṭ lō' yim'al pîw</em> = 'his mouth should not err in judgment.'</p>",
    "11": "<p><em>Peles ûmō'zĕnê mišpāṭ lYHWH</em> = 'A just balance and scales belong to the LORD' — YHWH is the ultimate standard of all measurement. The divine ownership of measuring instruments means that commercial dishonesty is not merely a social wrong but a theological offense. <em>Kol-'abnê-kis</em> = 'all the stones of the bag' = all the calibration weights.</p>",
    "12": "<p>'An abomination to kings to do evil' — <em>kî-bĕṣĕdāqāh yikkôn kissē'</em> = 'for by righteousness the throne is established.' The throne's stability is a function of the righteousness of its occupant; this is the standard prophetic critique (Amos, Isaiah, Jeremiah) applied to the wisdom context: power without righteousness is self-undermining.</p>",
    "13": "<p><em>Śiptê-ṣedeq reṣôn mĕlākîm</em> = 'Lips of righteousness are the delight of kings' — <em>reṣôn</em> (delight/favor) describes what the wise king values in counsel. <em>Wĕ'ōhēb dibēr yĕšārîm</em> = 'and one who speaks straight/upright things he loves.' The king who values honest counsel is functionally wise; the king who does not (see 14:35; 19:12) is a danger.</p>",
    "14": "<p><em>Za'ap-melek mal'ăkê māwet</em> = 'The wrath of the king is messengers of death' — the plural <em>mal'ăkê</em> (messengers) figures the king's anger as an agency that sends out death-agents. <em>Wĕ'îš ḥākām yĕkappĕrennāh</em> = 'but a wise man will appease/atone for it.' <em>Kāpar</em> (atone/cover) applied to pacifying the king's anger — wisdom is the instrument that deflects lethal power.</p>",
    "15": "<p><em>'ôr-pĕnê-melek ḥayyîm</em> = 'In the light of the king's face is life' — the king's approving look gives life; <em>ûrĕṣônô kĕ'āb malkôš</em> = 'and his favor is like a cloud of spring rain.' The <em>malkôš</em> (spring rain, late/latter rain) is the rain that causes the grain to mature in the final weeks before harvest — the most life-giving of rains. Royal favor is that precious and that productive.</p>",
    "16": "<p>'How much better to get wisdom than gold' (<em>qĕnôh ḥokmāh mah-ṭôb mizzāhāb</em>) — the comparative wisdom saying uses the commercial vocabulary of v8 (<em>qānāh</em> = acquire/buy). The parallel 'and to get understanding is to be chosen rather than silver' reinforces the value-comparison: wisdom beats both metals.</p>",
    "17": "<p><em>Mĕsillat yĕšārîm sûr mērā'</em> = 'The highway of the upright is turning away from evil' — <em>mĕsillāh</em> is the paved royal road, not a footpath. The deliberate road-avoidance of evil is the upright person's characteristic movement. <em>Šōmēr napšô nōṣēr darkô</em> = 'the one who guards his soul keeps his way.'</p>",
    "18": "<p><em>Lifnê-šeber gā'ôn</em> = 'Before destruction is pride' — the famous verse. <em>Gā'ôn</em> (pride/majesty) can be positive (divine majesty) or negative (human arrogance); here clearly the latter. <em>Gōbah rûaḥ lifnê kāšel</em> = 'and a haughty spirit before stumbling/falling.' The MKT 'Pride goes before destruction, and a haughty spirit before a fall' reproduces the standard English idiom derived from this verse; the Hebrew <em>gā'ôn</em> is more intense than 'pride' — it denotes presumptuous self-exaltation.</p>",
    "19": "<p>'Better to be lowly (<em>šĕpal-rûaḥ</em>, low of spirit) with the poor than to divide spoil with the proud' — the antithesis between true humility (voluntarily taken low position with those of low status) and triumphalist gain-sharing with the arrogant. The socioeconomic dimension is deliberate: wisdom chooses the social bottom over the prideful top.</p>",
    "20": "<p><em>Maśkîl 'al-dābār</em> = 'The one who attends wisely to a matter' (or 'who handles a word skillfully') <em>yimṣā' ṭôb</em> = 'will find good.' <em>Ûbôṭēaḥ baYHWH</em> = 'and blessed is the one who trusts in the LORD.' The two lines create an implied equation: skillful attention to affairs and trust in YHWH belong together; neither is separable from the other in Proverbs' wisdom theology.</p>",
    "21": "<p><em>Ḥăkam-lēb yiqqārē' nābôn</em> = 'The wise of heart will be called discerning' — <em>nābôn</em> (discerning) is the social recognition of inner wisdom. <em>Ûmeteq śĕpātayim yôsîp leqaḥ</em> = 'and sweetness of lips increases learning/reception' — the communicative dimension of wisdom: not only possessing understanding but conveying it with <em>meteq</em> (sweetness/pleasantness) that makes it receivable.</p>",
    "22": "<p><em>Mĕqôr ḥayyîm śĕkel bĕ'ālāyw</em> = 'A fountain of life is insight to its possessor' — the same fountain-of-life image as 13:14; 14:27 — wisdom as the source of life. <em>Ûmûsar 'ĕwîlîm 'iwwelet</em> = 'but the discipline of fools is folly' — discipline applied to the fool only produces more folly; the fool turns even correction into an expression of his nature.</p>",
    "23": "<p><em>Lēb ḥākām yaśkîl pîhû</em> = 'The heart of the wise makes his mouth wise/teach skillfully' — the internal-external connection: a wise heart produces wise speech. <em>Wĕ'al-śĕpātāyw yōsîp leqaḥ</em> = 'and on his lips it adds learning/persuasive power.' The wise person's words carry more weight because they arise from genuine understanding rather than mere rhetorical skill.</p>",
    "24": "<p><em>Nōpet ṣûpîm 'imrê nō'am</em> = 'Pleasant words are like honeycomb' — <em>nōpet ṣûpîm</em> is dripping/flowing honeycomb (the purest, finest honey). <em>Marpe' lā'etsem</em> = 'healing to the bones' — the physical metaphor for the restorative power of well-chosen words. The bones as the deepest bodily structure suggest that good speech heals at the most fundamental level.</p>",
    "25": "<p>Verbatim repetition of 14:12: 'There is a way that seems right to a man, but its end is the way to death' (<em>derek yāšār lipnê-'îš wĕ'aḥărîtāh darkê-māwet</em>). The repetition of the saying is intentional — it belongs to the center of ch16's meditation on divine sovereignty (vv1,9,33 frame the chapter) and human self-deception. The way that 'seems right' is the alternative to YHWH-ordered steps (v9).</p>",
    "26": "<p><em>Nepeš 'āmēl 'āmĕlāh-lô</em> = 'The soul/appetite of the laborer labors for him' — the worker is driven by his own <em>nepeš</em> (appetite/self). <em>Kî-'āpap 'ālāyw pîhû</em> = 'for his mouth urges/presses him' — hunger is the motor of labor; the bodily need drives the work. This is neutral observation, not critique: physical need is part of the created order that motivates human industry.</p>",
    "27": "<p><em>'Îš bĕliyya'al kōreh rā'āh</em> = 'A man of worthlessness digs evil' — <em>kārar</em> (dig) suggests deliberate labor to produce wickedness; evil doesn't happen accidentally for such a person, it is excavated. <em>Wĕ'al-śĕpātāyw kĕ'ēš ṣōrābet</em> = 'and on his lips is like scorching fire' — the speech of the worthless person burns those it touches.</p>",
    "28": "<p><em>'Îš tahpukôt yĕšallēaḥ mādon</em> = 'A man of perversities/distortions sends out strife' — <em>tahpukôt</em> (perversities) describes fundamental distortion of the moral order. <em>Wĕnirgan maphrid allûp</em> = 'and a whisperer separates close friends' — <em>nirgan</em> (whisperer/gossip) does maximal damage in the most intimate relationships; <em>allûp</em> = a close friend or intimate companion.</p>",
    "29": "<p><em>'Îš ḥāmās yĕpatteh rē'ēhû</em> = 'A violent man entices/seduces his neighbor' — <em>pātāh</em> (entice/seduce) is the word used for seduction in sexual contexts; the violent person uses persuasion before force. <em>Wĕhôlîkô bĕderek lō'-ṭôb</em> = 'and leads him in a way that is not good' — Proverbs' characteristic understatement for spiritual ruin.</p>",
    "30": "<p>'One who winks with his eyes (<em>'ōṣeh 'ênāyw</em>) to devise perverse things, one who purses his lips (<em>qōrēṣ śĕpātāyw</em>)' — the non-verbal communication of malicious intent. These are the same body-language indicators as 6:13-14: crooked dealings are signaled through eyes and lips before they are enacted in action. <em>Kille' rā'āh</em> = 'finishes/completes evil.'</p>",
    "31": "<p><em>Wĕśêbāh 'ăṭeret tipʾāret</em> = 'Grey/white hair is a crown of glory' — <em>śêbāh</em> (grey hair/old age) as a crown is unusual; typically crowns are given by wisdom (4:9). Here old age itself is the crown, but only <em>bĕderek ṣĕdāqāh timāṣē'</em> = 'when found in the way of righteousness.' Long life that has been righteous is the crown; long wicked life is not crowned.</p>",
    "32": "<p><em>'Erek 'appayim miggibôr</em> = 'Slow to anger is better than a warrior' — <em>'erek 'appayim</em> (long of nose/anger = patient/slow to anger) is the divine attribute of Exod 34:6 applied to the human sphere. <em>Ûmōšēl bĕrûḥô milōkēd 'îr</em> = 'and the one who rules his spirit is better than one who conquers a city' — the most demanding conquest is internal. The military vocabulary applied to self-mastery is deliberately ironic.</p>",
    "33": "<p><em>Haggôrāl yûṭal bĕḥêq</em> = 'The lot is cast into the lap' — the mechanism of lot-casting (Urim/Thummim; casting lots for decisions) is described; <em>ûmēYHWH kol-mišpāṭô</em> = 'but from the LORD is its every decision/judgment.' What appears to be chance is actually divine determination. This closes the divine-sovereignty inclusio of ch16 (vv1,9,33): YHWH governs the tongue (v1), the step (v9), and even the lot (v33).</p>"
  },
  "17": {
    "1": "<p><em>Ṭôb pat ḥărēbāh wĕšalwāh-bāh</em> = 'Better a dry morsel with quietness/peace in it' — <em>pat ḥărēbāh</em> = a dry/crumbled morsel (the opposite of fat, moist food). <em>Mibayit mālē' zibeḥê-rîb</em> = 'than a house full of sacrificial feasts with strife' — sacrificial feasts (<em>zibeḥê</em>) represent the height of abundance and religious occasion; the contrast is between austere peace and sumptuous conflict.</p>",
    "2": "<p><em>'Ebed maśkîl</em> = 'A wise servant' who rules over a disgraceful son — social mobility through wisdom: the slave who exercises wisdom surpasses the birth-right of the fool-son. <em>Ûbĕtôk 'aḥîm yḥaliq naḥalāh</em> = 'and among brothers he will share in the inheritance.' Wisdom overturns normal social hierarchy.</p>",
    "3": "<p><em>Maṣrēp lakkesep wĕkûr lazzāhāb</em> = 'A crucible/refining pot for silver and a furnace for gold' — <em>maṣrēp</em> (refining pot) and <em>kûr</em> (furnace/smelting furnace) are the metallurgical vessels; <em>ûbōḥēn libbôt YHWH</em> = 'but the tester of hearts is the LORD.' The divine smelting-test applies to the heart what the crucible applies to metal: YHWH's scrutiny purges and reveals what is genuinely valuable.</p>",
    "4": "<p><em>Mērēa' maqšîb 'al-śepat-'āwen</em> = 'An evildoer listens to wicked lips' — the audience shapes the speaker: those who listen to wickedness are themselves wicked. <em>Šeqer maqšîb 'al-lĕšôn hawwôt</em> = 'a liar pays attention to a destructive tongue' — the mutual reinforcement of wickedness in speech-listening: you listen to what you are.</p>",
    "5": "<p><em>Lō'ēg lārāš ḥērēp 'ōśēhû</em> = 'Whoever mocks the poor insults his Maker' (<em>'ōśēhû</em> = the one who made him) — the same creation-theology as 14:31. <em>Śāmēaḥ lĕ'ēd lō' yinnāqeh</em> = 'the one who rejoices at calamity will not go unpunished' — the prohibition on gloating extends to all suffering; malice in the face of others' disasters is an active moral failing.</p>",
    "6": "<p><em>'ăṭeret zĕqênîm bĕnê bānîm</em> = 'The crown of the elderly is grandchildren' — the multigenerational structure of wisdom-transmission: grandchildren are the elderly person's crown because they represent the continuation of the legacy. <em>Wĕtipʾeret bānîm 'ăbôtām</em> = 'and the glory of children is their fathers' — the bidirectional nature of generational honor: children bring honor to fathers; fathers are the crown of children.</p>",
    "7": "<p><em>Lō' nā'wāh lĕnābāl śepat-yeter</em> = 'Not fitting/appropriate for a fool is excellent speech' — <em>nābāl</em> (fool/knave) is the morally deficient person. The irony: fine speech in a fool's mouth is as incongruous as lying lips in a nobleman's. The implication is that speech quality must match character to be authentic; eloquent lies are more dangerous than clumsy truths.</p>",
    "8": "<p><em>'Eben-ḥēn haššōḥad bĕ'ênê bĕ'ālāyw</em> = 'A charm-stone/magical stone (<em>ḥēn</em>) is the bribe in the eyes of its owner' — the bribe is described as a jewel or lucky stone that seems to work like magic. <em>Bĕkol-'ăšer yipneh yaśkîl</em> = 'wherever it turns it prospers.' This is social observation without explicit moral comment — the effectiveness of bribery is noted; the condemnation is implicit in the broader context.</p>",
    "9": "<p><em>Mĕkasseh-peša' mĕbaqqēš 'ahăbāh</em> = 'Covering/overlooking a transgression seeks love' — <em>kāsāh</em> (cover) is a positive act here: not sweeping sin under the rug but choosing not to expose or repeat an offense, in service of relationship. The contrast: <em>šôneh bĕdābār maphrid allûp</em> = 'but repeating a matter separates close friends' — <em>allûp</em> again (v28); the intimate friendship most vulnerable to gossip.</p>",
    "10": "<p><em>Tērad gĕ'ārāh bĕmêbîn</em> = 'A rebuke sinks deeper into a discerning person' than a hundred blows into a fool. The receptivity to correction is the diagnostic of wisdom — not how much punishment is required, but how much truth is received. The discerning person is changed by a single word; the fool is unaffected by violence.</p>",
    "11": "<p><em>Ak-merî yĕbaqqēš-rā'</em> = 'Only/nothing but rebellion does the evil man seek' — <em>merî</em> (rebellion/contumacy) as the single definitive characteristic. <em>Ûmal'āk 'akzārî yĕšullaḥ-bô</em> = 'and a cruel messenger will be sent against him' — divine retribution in the form of a harsh emissary; what you cultivate is what you receive.</p>",
    "12": "<p><em>Pāgoš dōb šakkûl bĕ'îš</em> = 'Meet a bereaved bear rather than a fool in his folly' — the bereaved bear (<em>dōb šakkûl</em>) robbed of her cubs is one of the ancient world's most dangerous animals; the fool's danger exceeds even this. The comparison calibrates the lethality of the fool: the bear's danger is situational; the fool's is chronic and incorrigible.</p>",
    "13": "<p><em>Mēšîb rā'āh taḥat ṭôbāh</em> = 'One who returns evil for good' — the treachery of repaying good with evil is the deepest form of relational betrayal. <em>Lō'-tāmûš rā'āh mibbêtô</em> = 'evil will not depart from his house' — the principle of sowing and reaping (Gal 6:7 echoes this) applies to treachery: the household of the betrayer becomes the dwelling-place of the evil he returned.</p>",
    "14": "<p><em>Pōṭēr mayim rēšît mādon</em> = 'The beginning of strife is like letting out water' — <em>pōṭēr</em> (let out, release) of water describes the first crack in a dam: once the water is released, the whole structure collapses. The MKT 'start of conflict is like a crack letting out water' captures this vividly. <em>Ûlibnê hithraqqēaḥ hārîb</em> = 'so abandon the quarrel before it breaks open' — wisdom acts at the first sign of fracture, not after the flood.</p>",
    "15": "<p><em>Maṣdîq rāšā' ûmarší'a ṣaddîq</em> = 'Acquitting the wicked and condemning the righteous' — both are abominations to YHWH. The judicial perversion is double: falsely clearing the guilty and falsely condemning the innocent. This is the central prophetic concern (Isa 5:20,23; Amos 5:7; Mic 3:11) placed in the wisdom frame: miscarriage of justice is categorically intolerable to YHWH.</p>",
    "16": "<p><em>Lāmmāh-zeh mĕḥîr bĕyad-kĕsîl liqnôt ḥokmāh</em> = 'Why is there a price in the hand of a fool to buy wisdom, when he has no heart for it?' — the irony is economic: the fool might have the purchasing power but lacks the capacity to receive what wisdom offers. <em>Wĕlēb 'āyin</em> = 'no heart' — not absence of desire but absence of the necessary cognitive-moral organ for wisdom acquisition.</p>",
    "17": "<p><em>'Āhēb 'ohēb bĕkol-'ēt</em> = 'A friend loves at all times' — the 'at all times' (<em>bĕkol-'ēt</em>) is the mark of genuine friendship: not situational but constant. <em>Wĕ'āḥ lĕṣārāh yiwwālēd</em> = 'and a brother is born for times of adversity.' The friend as 'all-times' lover and the brother as 'adversity-born' companion: friendship transcends circumstance while brotherhood is revealed by it.</p>",
    "18": "<p><em>Ādam ḥăsar-lēb tôqēa' kāp</em> = 'A man lacking sense gives a pledge/strikes hands in surety' — echoing 6:1-5; the surety-pledge is the sign of deficient practical wisdom. <em>'ōrēb 'ărubāh lipnê rē'ēhû</em> = 'gives surety in the presence of his neighbor' — the public nature of the commitment makes it even more binding and more reckless.</p>",
    "19": "<p><em>'Ōhēb peša'</em> = 'One who loves transgression loves strife' — the love of sin produces communal damage as a natural output. <em>Magbîah petaḥô mĕbaqqēš-šāber</em> = 'one who raises his gate high seeks destruction' — the 'high gate' is probably an image of arrogance/ostentation that provokes conflict; 'seeking destruction' describes the inevitable result of proud self-assertion.</p>",
    "20": "<p><em>'Iqēš-lēb lō'-yimṣā'-ṭôb</em> = 'The crooked-of-heart does not find good' — <em>'iqēš</em> (crooked) is the same term as 16:28 (<em>tahpukôt</em>); fundamental distortion produces a life where good is inaccessible. <em>Wĕnehpāk bilšônô yippôl bĕrā'āh</em> = 'and the one perverted in his tongue falls into evil' — speech and character are inseparable in Proverbs; crooked speech is both symptom and cause of moral downfall.</p>",
    "21": "<p>'To have a fool for a son brings grief' (<em>lĕtûgāh hôledô</em>) — the parental perspective: the father's grief at a foolish son is deep precisely because it is personal, not abstract. <em>Wĕlō' yiśmaḥ 'ăbî nābāl</em> = 'and the father of a fool does not rejoice' — the double statement intensifies: not just sadness but absence of joy. Compare the prodigal son's father's joy at the son's return (Luke 15:24) as the inversion of this portrait.</p>",
    "22": "<p><em>Lēb śāmēaḥ yêṭib gēhāh</em> = 'A joyful heart (<em>śāmēaḥ</em>) makes good/is a good healing/medicine' — <em>gēhāh</em> (healing/cure) is the medical term; the joyful heart is therapeutic. <em>Wĕrûaḥ nĕkē'āh tĕyaббēš-gārem</em> = 'but a crushed/stricken spirit dries the bones' — the psychosomatic connection: inner spirit directly affects bodily health. Modern medical understanding of stress physiology resonates with this.</p>",
    "23": "<p><em>Šōḥad miḥêq rāšā' yiqqāḥ</em> = 'The wicked takes a bribe from the bosom' — <em>ḥêq</em> (bosom/fold) is where valuables were hidden in ancient clothing; the bribe is taken from its hiding place. <em>Lĕhaṭṭôt 'orḥôt mišpāṭ</em> = 'to pervert the paths of justice' — the specific damage of bribery: not merely corruption but the structural distortion of the justice system itself.</p>",
    "24": "<p><em>Pĕnê-mêbîn ḥokmāh</em> = 'Wisdom is before/in the face of the discerning' — the discerning person is always looking at wisdom, always attending to it. <em>Wĕ'ênê kĕsîl biqṣēh-'āreṣ</em> = 'but the eyes of a fool go to the ends of the earth' — the fool's gaze is scattered and unfocused; wisdom and folly are distinguished by where the eyes habitually rest.</p>",
    "25": "<p>'A foolish son is grief to his father and bitterness to her who bore him' (<em>kā'as lĕ'ābîw</em>) — the maternal-paternal grief is distinct: <em>kā'as</em> (vexation/anger) for the father; <em>memer</em> (bitterness) for the mother. The deeply personal nature of parental grief at a foolish child is not abstract moralism but the real relational cost of folly.</p>",
    "26": "<p><em>Gam 'ănôš laṣṣaddîq lō'-ṭôb</em> = 'Even to punish the righteous is not good' — the fundamental injustice of punishing the innocent. <em>Lehakkôt nĕdîbîm 'al-yōšer</em> = 'to strike nobles for what is right' — a secondary injustice: punishing the honorable for their integrity, which is a form of persecution of virtue.</p>",
    "27": "<p><em>Ḥōśēk 'ămārāyw dô'ēa' da'at</em> = 'The one who restrains his words knows knowledge' — <em>ḥāśak</em> (restrain/hold back) is the virtue of verbal restraint; the knowledgeable person recognizes that not every thought needs expression. <em>Wĕqar-rûaḥ 'îš tĕbûnāh</em> = 'and a cool spirit (<em>qar-rûaḥ</em>) is a person of understanding.' Cool-spirited is the antithesis of the hot-tempered person of 14:29; 16:32.</p>",
    "28": "<p><em>Gam 'ĕwîl maḥăriš ḥākām yēḥāšēb</em> = 'Even a fool who keeps silent is counted wise' — the paradox: silence can simulate wisdom even in the foolish. <em>'Ōṭēm śĕpātāyw nābôn</em> = 'the one who keeps his lips shut is discerning.' The implication is not that silence is always wisdom but that wisdom's primary visible marker — restrained speech — can be faked; genuine wisdom requires both the restraint and the inner reality.</p>"
  },
  "18": {
    "1": "<p><em>Lĕtā'ăwāh yĕbaqqēš niprad</em> = 'For his desire/appetite the one who separates himself seeks' — the enigmatic opening verse: the person who isolates himself (<em>niprad</em>) does so to pursue his own desire (<em>tā'ăwāh</em>). <em>Bĕkol-tûšîyyāh yitgallā'</em> = 'against all sound wisdom he breaks out' — the self-isolating person is described as acting against communal wisdom; the verse critiques antisocial individualism as desire-driven.</p>",
    "2": "<p><em>Lō' yāḥpoṣ kĕsîl bitbûnāh</em> = 'A fool has no delight in understanding (<em>tĕbûnāh</em>)' — not stupidity but deliberate disinterest. <em>Kî 'im-bĕhitgallôt libbô</em> = 'but only in revealing/exposing his heart' — the fool's goal in speech is self-expression, not learning or communication. The diagnostic: what is your speech for?</p>",
    "3": "<p><em>Bĕbô'-rāšā' bā' gam-bûz</em> = 'When the wicked comes, comes also contempt' — the wicked person brings an atmosphere of contempt with him; wickedness and contempt are package-deal companions. <em>Wĕ'im-qālôn ḥerpāh</em> = 'and with dishonor comes reproach' — a descending sequence: wickedness → contempt → dishonor → reproach.</p>",
    "4": "<p><em>Mayim 'ămuqqîm dibrê pî-'îš</em> = 'Deep waters are the words of a man's mouth' — the depth of speech is the depth of the person; <em>naḥal nōbēa' mĕqôr ḥokmāh</em> = 'a flowing/gushing stream is the fountain of wisdom.' Two water-images in parallel: deep waters suggest the unfathomable resources of the wise person's speech; the flowing brook suggests accessibility and generosity. See also 20:5.</p>",
    "5": "<p><em>Śe'ēt pĕnê rāšā' lō'-ṭôb</em> = 'To show partiality/lift the face of the wicked is not good' — <em>nāśā' pānîm</em> (lift the face = show favor/partiality) in legal contexts is the act of letting the guilty off. <em>Lĕhaṭṭôt ṣaddîq bammišpāṭ</em> = 'to thrust aside the righteous in judgment' — the double injustice of the corrupt court echoes 17:15.</p>",
    "6": "<p><em>Śiptê ḵĕsîl yābō'û bĕrîb</em> = 'The lips of a fool come into strife/contention' — the fool's speech generates conflict automatically. <em>Ûpîw lĕmahălummôt yiqrā'</em> = 'and his mouth calls for blows' — the fool's mouth invites physical punishment as the natural response to the offense his words generate.</p>",
    "7": "<p><em>Pî-ḵĕsîl mĕḥittāh-lô</em> = 'The fool's mouth is his ruin/destruction' (<em>mĕḥittāh</em> = destruction/terror/ruin) — the auto-destruction of the fool through speech. <em>Wĕśĕpātāyw môqēš napšô</em> = 'and his lips are a trap for his soul' — the lips that set the trap in which the soul is caught; speech as self-entrapment.</p>",
    "8": "<p><em>Dibrê nirgan kĕmitlahamîm</em> = 'The words of a gossip/whisperer are like delicacies' (<em>mithlahamîm</em> = dainties/sweet morsels) — the appetizing quality of gossip: it is consumed greedily. <em>Wĕhēm yārdû ḥadrê-bāṭen</em> = 'and they go down into the inner chambers of the belly' — gossip enters the deep interior of the listener and cannot easily be expelled; once absorbed, it becomes part of the hearer's inner life.</p>",
    "9": "<p><em>Gam mitrappeh bĕmĕla'ktô</em> = 'Also the one who is slack/negligent in his work' — the slothful worker is placed in explicit parallel with the destroyer: <em>'āḥ hû' lĕba'al mašḥît</em> = 'he is a brother to the one who destroys.' The apparently mild sin of laziness in one's work is categorized as destroying: negligence and active destruction belong in the same moral family.</p>",
    "10": "<p><em>Migdal-'ōz šēm YHWH</em> = 'A strong/mighty tower is the name of the LORD' — <em>migdal 'ōz</em> (tower of strength) is a military fortress metaphor applied to YHWH's name. <em>Bô-yārûṣ ṣaddîq wĕniśgāb</em> = 'the righteous runs into it and is set on high/protected' — <em>śāgab</em> (be set on high, inaccessible to attack) describes the military safety of the elevated fortification. The righteous person's refuge is not a place but a name — YHWH's personal identity and character.</p>",
    "11": "<p><em>Hôn 'āšîr qiryat 'uzzô</em> = 'The wealth of the rich is his strong city (<em>qiryat 'uzzô</em>)' — the rich person treats wealth as a fortress; <em>ûkĕḥômāh niśgābāh bĕmaśkîtô</em> = 'and like a high wall in his imagination/conceit.' The word <em>maśkît</em> (imagination/mental picture) reveals that the wealthy person's fortress is ultimately psychological — the protection exists in how he perceives his wealth, not in its actual power. Contrast with v10's genuine fortress.</p>",
    "12": "<p><em>Lifnê-šeber yigbah lēb-'îš</em> = 'Before destruction the heart of a man is proud' — echoing 16:18 but varying the verb: <em>gābah</em> (be high/proud). <em>Wĕlifnê kābôd 'ănāwāh</em> = 'and before honor is humility' — the reversal pattern of the kingdom: what precedes honor is the opposite of what human nature expects. See Luke 14:11; James 4:10.</p>",
    "13": "<p><em>Mēšîb dābār beṭerem yišmā'</em> = 'The one who gives an answer before he hears' — premature response before adequate listening. <em>'Iwwelet hî'-lô ûkĕlimmāh</em> = 'it is folly and shame to him' — the fool exposes himself by speaking before understanding; the shame is both cognitive (he's wrong) and social (he's seen to be wrong).</p>",
    "14": "<p><em>Rûaḥ-'îš yĕkalkēl maḥălēhû</em> = 'The spirit of a man sustains/bears his illness' — resilient inner spirit enables endurance of physical suffering; <em>wĕrûaḥ nĕkē'āh mî yiśśā'ennāh</em> = 'but a crushed spirit, who can bear it?' The crushed spirit (<em>nĕkē'āh</em>, stricken/smitten) is the one load the human frame cannot carry; external suffering is more bearable than internal collapse.</p>",
    "15": "<p><em>Lēb nābôn yiqneh-da'at</em> = 'The discerning/understanding heart acquires knowledge' — active pursuit: <em>qānāh</em> (acquire) as in 4:5,7. <em>Wĕ'ōzen ḥăkāmîm tĕbaqqēš-da'at</em> = 'and the ear of the wise seeks knowledge' — the complementary image: the discerning heart acquires and the wise ear seeks; both instruments of reception are active.</p>",
    "16": "<p><em>Mattān 'ādām yarḥîb lô</em> = 'A gift of a man makes room for him' (<em>rāḥab</em> = make wide/spacious) — the gift opens doors and creates social access. <em>Wĕlifnê gĕdōlîm yanḥennû</em> = 'and it leads him before great men' — gifts as social currency enabling access to power. The observation is pragmatic, not endorsement of bribery (cf. 17:23).</p>",
    "17": "<p><em>Ṣaddîq hārī'šôn bĕrîbô</em> = 'The first to state his case seems righteous' — the rhetorical advantage of being first: before cross-examination, any case appears strong. <em>Ûbā' rē'ēhû ûbĕqārô</em> = 'but his neighbor comes and searches/examines him' — judicial process requires adversarial scrutiny; the truth of any claim is tested by challenge. This is the wisdom basis for adversarial legal systems.</p>",
    "18": "<p><em>Midyānîm yašbît haggôrāl</em> = 'Lots put an end to contentions' — the lot as a conflict-resolution mechanism removes the human element of partisanship; YHWH controls the lot (16:33). <em>Ûbên 'aṣûmîm yiphrîd</em> = 'and it separates between the powerful' — when human negotiation between strong parties fails, divine arbitration through the lot provides a result that both must accept.</p>",
    "19": "<p><em>'Āḥ nipšā' miqiryat-'āz</em> = 'A brother offended is harder than a strong city' — the most difficult reconciliation is with one you were closest to; the betrayed intimate becomes impenetrable. <em>Ûmdānîm kimbrîaḥ 'armon</em> = 'and contentions are like the bars of a fortress' — the relational barricade that follows betrayal between brothers is structurally as resistant as castle-bars.</p>",
    "20": "<p><em>Mippĕrî pî-'îš tiśba' biṭnô</em> = 'From the fruit of his mouth a man's belly is satisfied' — the harvest-metaphor for speech-consequences: what comes from the mouth returns to nourish or harm the speaker. <em>Tĕbû'at śĕpātāyw yiśbā'</em> = 'the harvest of his lips fills him' — the speaker reaps what he sows with his words.</p>",
    "21": "<p><em>Māwet wĕḥayyîm bĕyad-lāšôn</em> = 'Death and life are in the hand/power (<em>yād</em>) of the tongue' — the most sweeping claim in Proverbs about the power of speech. <em>Yād</em> (hand) is the hand of power/agency; the tongue holds life and death in its power as a hand holds a tool. <em>Wĕ'ōhăbêhā yō'kal piryāh</em> = 'and those who love it will eat its fruit' — the tongue-lover reaps exactly what speech produces: life or death.</p>",
    "22": "<p><em>Māṣā' 'iššāh māṣā' ṭôb</em> = 'Whoever finds a wife finds a good thing' — <em>māṣā'</em> (find) with <em>ṭôb</em> (good thing/goodness) frames marriage as a discovered gift, not a made arrangement. <em>Wayyāpeq rāṣôn mēYHWH</em> = 'and receives favor (<em>rāṣôn</em>) from the LORD' — the good wife is a form of YHWH's favor; marriage is framed as theologically significant, not merely socially convenient.</p>",
    "23": "<p><em>Taḥănûnîm yĕdabbēr-rāš</em> = 'With supplications/entreaties the poor speaks' — the asymmetry of social speech: the poor must beg; <em>wĕ'āšîr ya'aneh 'azzôt</em> = 'but the rich answers harshly/rudely' (<em>'azzôt</em> = harsh/insolent words). Proverbs observes the economic sociology of speech: your social position determines both how you speak and how you are heard.</p>",
    "24": "<p><em>'Îš rē'îm lĕhitrō'ēa'</em> = 'A man of many companions may come to ruin' (or 'must show himself friendly') — the opening phrase is disputed: <em>lĕhitrō'ēa'</em> = 'to show friendship/associate' or 'to his own ruin.' <em>Wĕyēš 'ōhēb dābēq mē'āḥ</em> = 'but there is a friend who sticks closer than a brother' — the quality-vs-quantity contrast: a single faithful friend who <em>dābaq</em> (cleaves/clings) surpasses the shallow social network of many companions.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'proverbs')
    merge_comm(existing, PROVERBS)
    save_comm('mkt-original', 'proverbs', existing)
    total = sum(len(v) for v in PROVERBS.values())
    print(f'proverbs mkt-original: wrote {total} verses for ch 16–18')

if __name__ == '__main__':
    main()
